\displaystyle{\begin{aligned}[t]
    \frac{3}{20} \div \left(-\frac{5}{8}\right)
        \amp = \frac{3}{20} \cdot \left(-\frac{8}{5}\right) \amp \hbox{We can divide the first denominator and the second numerator by 4.}\\
        \amp = \frac{3}{5 }\cdot\left(-\frac{2}{5}\right) \\
        \amp = -\frac{6}{25}
\end{aligned}
    }
